"use client";

import { Presence as ArkPresence } from "@ark-ui/react/presence";
import type React from "react";
import { cn } from "@/lib/utils";

const presenceClass = cn(
  "flex items-center justify-center rounded-md border bg-muted px-4 py-6 font-medium text-foreground text-sm",
  "data-[state=open]:fade-in-0 data-[state=open]:zoom-in-95 data-[state=open]:animate-in",
  "data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95 data-[state=closed]:animate-out"
);

const Presence = (props: React.ComponentProps<typeof ArkPresence>) => {
  const { className, ...rest } = props;
  return (
    <ArkPresence
      className={cn(presenceClass, className)}
      data-slot="presence"
      {...rest}
    />
  );
};

export { Presence };
